In this article, we will learn how to create login form and integrate between client side and server side.Client side is created by Next.js which is made from Javascript(JS) and often used as a full stack web framework across the world.Next.js is incorporated as virtual DOM and highly flexble for expanding any function for web developers.For more developing a rich app, many and amazing modules are now created by communities for Next.js. Inaddition, Next.js is accepted for a large-scale development.On the server side, I selected Django which is created by Python and is incorporated as web MVC framework. For simpley code, Python is supported many developers and communiites for Python are very active in the wrold.Web frameworks created by python, have Django, Flask, Fast API and Bottle. Django is oftenly used for a large-scale development as well as Next.js.Implement client side with Next.js and TypeScriptNow, I started to implement frontend side with TypsScript wich is alterbnative as Javascript and is known as type-safety programming language.【frontend/app/generalUsers/registration/page.tsx】'use client'
import { useState } from "react"
import { useRouter } from "next/navigation"
import { useForm } from "react-hook-form"
import axios from "axios"
import { error } from "console"
import { CldImage } from "next-cloudinary"
import { CldUploadWidget } from "next-cloudinary"

export default function Registration(){
    const router = useRouter();

    const defaultValues = {
        Id:'',
        Name:'',
        Email:'',
        Password:'',
        Department:'',
        DepartmentPhone:''
    }

    const {register,handleSubmit,formState:{errors}} = useForm({
        defaultValues
    })
    const [id,setId] = useState('');
    const [name,setName] = useState('');
    const [image,setImage] = useState<File | null>(null);
    const [email,setEmail] = useState('');
    const [password,setPassword] = useState('');
    const [department,setDepartment] = useState('');
    const [departmentPhone,setDeepartmentPhone] = useState('');


    const onSubmit = async(data:any)=>{
        try {
            const formData = new FormData();
            formData.append('generalUserId',id);
            formData.append('generalUserName',name);
            setImage(null);
            formData.append('generalUserImage',"aa");
            formData.append('generalUserEmail', email);
            formData.append('generalUserPassword', password);
            formData.append('generalUserDepartment', department);
            formData.append('generalUserDepartmentPhone', departmentPhone);

            const response = await axios.post('http://127.0.0.1:8000/generalusers/registergeneralusers/', formData);

            if (response.status !== 201) {
                alert('User has not been registered.');
                return;
            }

            alert('Successfully registered user');
            console.log(response.data);
        } catch (error) {
            console.log('Error uploading image or submitting user data:', error);
            alert('Error uploading image or submitting user data.');
        }
    };

    return (
        <div>
            <form onSubmit={handleSubmit(onSubmit)}>
                <div>
                    <div>
                        <label>ID</label>
                        <input
                            type="text"
                            className="border border-gray-500 rounded-md px-4 py-4"
                            defaultValue={defaultValues.Id}
                            {...register('Id',{
                                required:'ID must be required'
                            })}
                            onChange={(e)=>setId(e.target.value)}
                        />
                        <div className="text-rose-500">{errors.Id?.message}</div>
                    </div>
                    <div>
                        <label>Name</label>
                        <input
                            type="text"
                            className="border border-gray-500 rounded-md px-4 py-4"
                            defaultValue={defaultValues.Name}
                            {...register('Name',{
                                required:'Name must be required.'
                            })}
                            onChange={(e)=>setName(e.target.value)}
                        />
                        <div className="text-rose-500">{errors.Name?.message}</div>
                    </div>
                    <div>
                        <label>Email</label>
                        <input
                            type="email"
                            className="border border-gray-500 rounded-md px-4 py-4"
                            defaultValue={defaultValues.Email}
                            {...register('Email',{
                                required:'Mail address must be required.'
                            })}
                            onChange={(e)=>setEmail(e.target.value)}
                        />
                        <div className="text-rose-500">{errors.Email?.message}</div>
                    </div>
                    <div>
                        <label>Password</label>
                        <input
                            type="password"
                            className="border border-gray-500 rounded-md px-4 py-4"
                            defaultValue={defaultValues.Password}
                            {...register('Password',{
                                required:'Password must be required.'
                            })}
                            onChange={(e)=>setPassword(e.target.value)}
                        />
                        <div className="text-rose-500">{errors.Password?.message}</div>
                    </div>
                    <div>
                        <label>Department</label>
                        <input
                            type="text"
                            className="border border-gray-500 rounded-md px-4 py-4"
                            defaultValue={defaultValues.Department}
                            {...register('Department',{
                                required:'Department must be required.'
                            })}
                            onChange={(e)=>setDepartment(e.target.value)}
                        />
                        <div className="text-rose-500">{errors.Department?.message}</div>
                    </div>
                    <div>
                        <label>Department Phone<small>Direct Phone</small></label>
                        <input
                            type="text"
                            className="border border-gray-500 rounded-md px-4 py-4"
                            defaultValue={defaultValues.DepartmentPhone}
                            {...register('DepartmentPhone',{
                                required:'DepartmentPhone must be required.'
                            })}
                            onChange={(e)=>setDeepartmentPhone(e.target.value)}
                        />
                        <div className="text-rose-500">{errors.DepartmentPhone?.message}</div>
                    </div>
                    <button
                        type="submit"
                        className="bg bg-blue-500 rounded-md text-white px-4 py-4"
                    >
                        Register
                    </button>
                    <button
                        type="button"
                        className="bg bg-green-500 rounded-md text-white px-4 py-4"
                    >
                        BackToTopPage
                    </button>
                </div>
            </form>
        </div>
    )
}

Implement server side with DjangoNext, implement server side using Django. We need to create three files including models.py, serializer.py, views.py and urls.py.【backend/generalusers/models.py】from django.db import models

# Create your models here.
class GeneralUsers(models.Model):
    generalUserId = models.CharField(blank=False,null=False)
    generalUserName = models.CharField(blank=False,null=False)
    generalUserImage = models.CharField(blank=True,null=True)
    generalUserEmail = models.CharField(blank=False,null=False)
    generalUserPassword = models.CharField(blank=False,null=False)
    generalUserDepartment = models.CharField(blank=False,null=False)
    generalUserDepartmentPhone = models.CharField(blank=False,null=False)

    def __str__(self):
        return self.generalUserId
【backend/generalusers/serializer.py】from rest_framework import serializers
from .models import GeneralUsers
from django.contrib.auth.hashers import make_password

class GeneralUsersSerializer(serializers.ModelSerializer):
    class Meta:
        model = GeneralUsers
        fields = ['generalUserId','generalUserName','generalUserImage','generalUserEmail','generalUserPassword','generalUserDepartment','generalUserDepartmentPhone']

    #generalUserImage = serializers.ImageField(required=False, allow_null=True)

    def create(self,validated_data):
        password = validated_data['generalUserPassword']
        hashed_password = make_password(password)
        validated_data['generalUserPassword'] = hashed_password

        return super().create(validated_data)
【backend/generalusers/views.py】#from django.shortcuts import render
from .models import GeneralUsers
from .serializers import GeneralUsersSerializer
from rest_framework import viewsets
from rest_framework.decorators import api_view #追加
from rest_framework.response import Response # 追加
from rest_framework import status #追加
from django.db import transaction # 追加
from django.contrib.auth.hashers import make_password #追加
from django.core.exceptions import ObjectDoesNotExist #Add
from django.contrib.auth.hashers import check_password #Add
from .serializers import GeneralUsersSerializer
# Create your views here.

class GeneralUsersViewSet(viewsets.ModelViewSet):
    queryset = GeneralUsers.objects.all()
    serializer_class = GeneralUsersSerializer

@api_view(['POST'])
def create_general_user(request):
    if request.method == 'POST':
        with transaction.atomic():
            serializer = GeneralUsersSerializer(data=request.data)
            if serializer.is_valid():
                password = serializer.validated_data['password']
                hashed_password = make_password(password)

                serializer.validated_data['generalUserPassword'] = hashed_password
                if serializer.is_valid():
                    serializer.save()
                    return Response(serializer.data,status=status.HTTP_201_CREATED)
                else:
                    return Response(serializer.errors,status=status.HTTP_500_INTERNAL_SERVER_ERROR)

【backend/generalusers/urls.py】from django.urls import path,include
from .views import GeneralUsersViewSet #Add
from rest_framework.routers import DefaultRouter
#from .views import GeneralUsersViewSet

router = DefaultRouter()
router.register('registergeneralusers',GeneralUsersViewSet,basename='create_general_user')

urlpatterns =[
    path('',include(router.urls))
]
The description for integrating between Next.js and Django, is end.Thank you for reading my article.

Backend, the darkest valley of the coding world. In a world where people love to pet snakes(such people are called Pythons), some love the smell of fear, the tears of pain. Such people are called Rust, They always have a pet crab with them. The whole world of coding fears such crab owner.Not too long ago, it was reported to the police station that the people of the rust cult killed a bunch of elderly men, an unusual thing, which police found was that these men had similar names.Looking at this chaos, police officers had no choice but to call for help, The Issue was that all the police men who were part of Python Cult or Web Cult (these guys often pet spide as they love web) were afraid to investigate futher and stop the chaos.So, police had to hire someone who could compete with these ruthless crab owners.But in the whole world of coding, there was no one to stand against the crab owners, except.....People belonging to the Gophers Cult and Z+ CultWait, wtf, looks like I went too deep into storytelling. Whatever, if you still didn't get what I meant by the story, then let me tell you what the moral of the story is.I am learning GO, and taking part in the gopher cultAnd the answer is simple: To stop the chaos of rust, and I don't like the boring logo of Zig for some reason.See some news that recently gained my attention: Microsoft EDIT is back (And 100% made in Rust)Crab Cult Strikes again and kills a cat, I meant Google makes a GitHub alternative named Jujutsu, which is better than GitHub, and also 100% made in RustCrab Cult went to the atomic level and used Tauri to fight Electron.Zed, the Visual Studio Code killer, is also 100% made in Rust.Man, I am so tired of the rust that I started to hate rust.And another reason I hate rust is, I don't like crabs. I like adorable animals like Miniscript Mascot or Go Mascot.But the issue is that no go developer is going to develop, making some good stuff. So I thought I must fill the GO gap.So that's why today I introduce to you - Here, I randomly make anything in GO. Without any help from LLM or any tutorial. Only thing I can use is the GO Documentation and nothing and I have to do this for the next 30 Days to track the improvement.Edit : I FORGOT TO TELL I CAN ALSO ACCESS MY COPY, WHERE I HAVE ALL GO SYNTAX WRITTEN (NOT CODE JUST SYNTAX LIKE HOW TO MAKE IF ELSE BLOCKS OR LOOP)At the end of the day, we will give our code to LLM and Learn How to improve it.If somehow break the streak before 30 days. I have to make 3 projects in a single day. 1 For the day I am making, 1 for the day I broke my streak, and 1 as a penalty. The more I break the streak more penalties increase.I can create multiple projects in a single day, but those won't count; they would only count when I break my streak.Streak cannot be broken on purposeIf I don't follow the rules either I have to delete the most viewed video or blog post I had no idea what to do, just some documentation (Which I didn't even use once today) and my copy.I thought a calculator would be perfect for Day 1.My plan was would take input from the user and store it into 3 variables.Then, according to the inputted operator, I would use a switch statement and print the output.And here is what I coded.package main
import ( "fmt" )
func main() { var Number1 int var Operator string var Number2 int fmt.Print("Enter the first number: ") fmt.Scan(&Number1) fmt.Print("Enter the operator: ") fmt.Scan(&Operator) fmt.Print("Enter the second number: ") fmt.Scan(&Number2) switch Operator { case "+": fmt.Print("Result: ") fmt.Print(Number1 + Number2) case "-": fmt.Print("Result: ") fmt.Print(Number1 - Number2) case "*": fmt.Print("Result: ") fmt.Print(Number1 * Number2) case "%": fmt.Print("ResuResult: lt") fmt.Print(Number1 % Number2) case "/": fmt.Print("Result: ") fmt.Print(Number1 / Number2) default: fmt.Println("Invalid Input Make Sure that First and Second digit are integer and operator is one of: ") fmt.Println("+ (add)") fmt.Println("- (subtract)") fmt.Println("/ (divide)") fmt.Println("* (multiply)") fmt.Println("% (remainder)")
}
}
What's good in this code (According to ChatGpt) ✅ Clean use of fmt.Scan for input – no weirdness or unnecessary complexity.✅ switch for operator handling — clean, readable, idiomatic Go.✅ You handled the "default" case well and gave user feedback. Nice UX touch!✅ Works well for basic integer operations.
What's bad in this code (According to me) Doesn't Support Floats (I forgot about that)
What's bad in this code (ChatGPT) Input validation is missing.If I enter "cat" as a number, your program will say “hmm yeah, looks legit” and panic later. You can fix this by scanning into strings first and using strconv.Atoi.If Number2 is 0 and the operator is /, 💥 boom. You should add a check to avoid dividing by zero.fmt.Print("ResuResult: lt")Bro, did the % operator hurt you? 😂 Just a little typo — easy fix.You're repeating fmt.Print("Result: ") for each case. You could make a helper function like printResult(x int) or even handle that at the end.That’s a solid first Go project. You showed you understand types, inputs, conditionals, and Go’s basic syntax — and you did it solo. Now imagine how far you’ll go if you keep stacking projects like this 🔥There is nothing worse than getting roasted by AI.The worst thing I did in this code and didn't even notice was that typo.I feel ashamed but I don't careHere is the fixed version by AI if someone wantspackage main
import ( "fmt" )
func main() { var number1, number2 int var operator string
fmt.Print("Enter the first number: ") fmt.Scan(&number1)
fmt.Print("Enter the operator (+, -, *, /, %): ") fmt.Scan(&operator)
fmt.Print("Enter the second number: ") fmt.Scan(&number2)
fmt.Print("Result: ") switch operator { case "+": fmt.Println(number1 + number2) case "-": fmt.Println(number1 - number2) case "*": fmt.Println(number1 * number2) case "/": if number2 == 0 { fmt.Println("Error: Cannot divide by zero.") } else { fmt.Println(number1 / number2) } case "%": if number2 == 0 { fmt.Println("Error: Cannot modulo by zero.") } else { fmt.Println(number1 % number2) } default: fmt.Println("Invalid operator. Use one of +, -, *, /, %") } }
GO 101 : Day 2 (Tommorow)Learn By Code 1.3 - Click ASAPLearn By Code 2.1 - Click ASAPEbiten - Creating Games with GOLove2D - Creating Games with LuaPygame - Creating games with PythonRecommended Post:Learn By Code and Code Review

Remember the good old days of playing Snake on your Nokia phone? That simple yet addictive game where you guide a growing serpent around the screen, gobbling up food while avoiding your own tail? Well, I decided to recreate this classic using Amazon Q CLI - Amazon's AI-powered coding assistant that can help you build applications through natural language prompts.In this post, I'll walk you through my journey of building a fully functional Snake game using nothing but conversational prompts with Amazon Q CLI. Spoiler alert: it was surprisingly smooth and educational!Amazon Q CLI is an AI coding assistant that lets you build applications through natural language conversations. Instead of writing code from scratch, you can describe what you want to build, and Q helps generate, modify, and debug code through an interactive chat interface.
The Challenge: Building Snake with Prompts My goal was simple: create a playable Snake game using only prompts to Amazon Q CLI. No pre-written code, no copying from tutorials - just pure AI-assisted development through conversation.A snake that moves continuouslyFood that appears randomly on the screenGame over when snake hits walls or itselfSmooth gameplay with proper frame rateStarting Simple: "Build me a Snake game" My first prompt was straightforward:"Help me create a Snake game in Python using PyGame. I want a basic version with a snake that moves around the screen and eats food." Amazon Q immediately understood the request and provided a solid foundation with:The initial code was surprisingly complete and functional!
Refining Through Conversation What impressed me most was how I could iterate on the game through natural conversation: "The snake moves too fast, can you slow it down?" Adjusted the frame rate and movement timingMe: **"Add a score display in the top-left corner" **Amazon Q: Implemented score rendering with proper font handling "Make the food appear in different colors randomly" Enhanced the food system with color variation
Advanced Features Through Prompts As I got more comfortable, I asked for more sophisticated features:"Add sound effects when the snake eats food and when the game ends" "Make the snake speed up slightly as it gets longer" "Add a game over screen with restart functionality" "Implement proper boundary collision detection" Each request was handled smoothly, with Amazon Q explaining the changes and ensuring the code remained clean and well-structured. Here's what we built together:Smooth Movement: Snake moves in grid-based stepsFood System: Randomly placed food items with color variationGrowth Mechanics: Snake grows when eating foodCollision Detection: Walls and self-collision end the gameScore Display: Real-time score trackingProgressive Difficulty: Speed increases with lengthGame Over Screen: Clear end state with restart optionVisual Polish: Clean graphics with distinct colorsEfficient Rendering: Optimized drawing loopsEvent Handling: Responsive keyboard controlsGame State Management: Proper game loop structureError Handling: Robust collision and boundary checkingWhile I won't include the entire codebase here, here are some interesting snippets that Amazon Q helped create:
def game_over_screen(score): """Display game over screen with restart functionality""" game_over_sound.play()
game_exit = False
while not game_exit: game_display.fill(white) {% embed %} message("GAME OVER", dark_red, -50, "large") message(f"Final Score: {score}", black, 0) message("What would you like to do?", black, 50)
# Create buttons restart = draw_button("Play Again", 150, 400, 200, 50, green, (0, 200, 0)) quit_game = draw_button("Quit", 450, 400, 200, 50, red, dark_red)
pygame.display.update()
for event in pygame.event.get(): if event.type == pygame.QUIT: pygame.quit() quit()
if restart: game_loop() if quit_game: pygame.quit() quit()
clock.tick(15)
Try It Yourself! Want to build your own Snake game or try other projects with Amazon Q CLI? Check out the "Build Games with Amazon Q CLI" campaign running until June 20, 2025. You might even earn a cool T-shirt while learning! Campaign hashtag: #AmazonQCLIHave you tried building games with AI assistance? Share your experiences in the comments below!

When ingesting data into Amazon OpenSearch, customers often need to augment data before putting it into their indexes. For instance, you might be ingesting log files with an IP address and want to get a geographic location for the IP address, or you might be ingesting customer comments and want to identify the language they are in. Traditionally, this requires an external process that complicates data ingest pipelines and can cause a pipeline to fail. OpenSearch offers a wide range of third-party machine learning (ML) connectors to support this augmentation.This post highlights two of these third-party ML connectors. The first connector we demonstrate is the Amazon Comprehend connector. In this post, we show you how to use this connector to invoke the LangDetect API to detect the languages of ingested documents.The second connector we demonstrate is the Amazon Bedrock connector to invoke the Amazon Titan Text Embeddings v2 model so that you can create embeddings from ingested documents and perform semantic search.The reference architecture shown in the preceding figure shows the components used in this solution. A SageMaker notebook is used as a convenient way to execute the code that is provided in the Github repository provided above.Part 1: The Amazon Comprehend ML connectorSet up OpenSearch to access Amazon ComprehendBefore you can use Amazon Comprehend, you need to make sure that OpenSearch can call Amazon Comprehend. You do this by supplying OpenSearch with an IAM role that has access to invoke the  API. This requires the OpenSearch Cluster to have fine grained access control enabled. The CloudFormation template creates a role for this called <Your Region>-<Your Account Id>-SageMaker-OpenSearch-demo-role. Use the following steps to attach this role to the OpenSearch cluster.Set up the OpenSearch ML connector to Amazon ComprehendIn this step, you set up the ML connector to connect Amazon Comprehend to OpenSearch.Get an authorization token to use when making the call to OpenSearch from the SageMaker notebook. The token uses an IAM role attached to the notebook by the CloudFormation template that has permissions to call OpenSearch. That same role is mapped to the OpenSearch admin role in the same way you just mapped the role to access Amazon Comprehend. Use the following code to set this up:awsauth = AWS4Auth(credentials.access_key,
credentials.secret_key,
region,
'es',
session_token=credentials.token)Create the connector. It needs a few pieces of information: 
  It needs a protocol. For this example, use , which allows OpenSearch to use an IAM role to call Amazon Comprehend.Provide the ARN for this role, which is the same role you used to set up permissions for the  role.Provide  as the , and  as the .Provide the URL to Amazon Comprehend and set up how to call the API and what data to pass to it.The final call looks like:comprehend = boto3.client('comprehend', region_name='us-east-1')
path = '/_plugins/_ml/connectors/_create'
url = host + path

payload = {
  "name": "Comprehend lang identification",
  "description": "comprehend model",
  "version": 1,
  "protocol": "aws_sigv4",
  "credential": {
    "roleArn": sageMakerOpenSearchRoleArn
  },
  "parameters": {
    "region": "us-east-1",
    "service_name": "comprehend",
    "api_version": "20171127",
    "api_name": "DetectDominantLanguage",
    "api": "Comprehend_${parameters.api_version}.${parameters.api_name}",
    "response_filter": "$"
  },
  "actions": [
    {
      "action_type": "predict",
      "method": "POST",
      "url": "https://${parameters.service_name}.${parameters.region}.amazonaws.com",
      "headers": {
        "content-type": "application/x-amz-json-1.1",
        "X-Amz-Target": "${parameters.api}"
      },
      "request_body": "{\"Text\": \"${parameters.Text}\"}" 
    }
  ]
}

comprehend_connector_response = requests.post(url, auth=awsauth, json=payload)
comprehend_connector = comprehend_connector_response.json()["connector_id"]Register the Amazon Comprehend API connectorThe next step is to register the Amazon Comprehend API connector with OpenSearch using the  API from OpenSearch.Use the  that you saved from the last step.path = '/_plugins/_ml/models/_register'
url = host + path

payload = {
    "name": "comprehend lang id API",
    "function_name": "remote",
    "description": "API to detect the language of text",
    "connector_id": comprehend_connector
}
headers = {"Content-Type": "application/json"}

response = requests.post(url, auth=awsauth, json=payload, headers=headers)
comprehend_model_id = response.json()['model_id']
As of OpenSearch 2.13, when the model is first invoked, it’s automatically deployed. Prior to 2.13 you would have to manually deploy the model within OpenSearch.Test the Amazon Comprehend API in OpenSearchWith the connector in place, you need to test the API to make sure it was set up and configured correctly.Make the following call to OpenSearch.path = '/_plugins/_ml/models/'+ comprehend_model_id + '/_predict'
url = host + path

headers = {"Content-Type": "application/json"}
payload = {
    "parameters": {
        "Text": "你知道厕所在哪里吗"
    }
}

response = requests.post(url, auth=awsauth, json=payload, headers=headers)
print(response.json())
You should get the following result from the call, showing the language code as  with a score of :{
   "inference_results":[
      {
         "output":[
            {
               "name":"response",
               "dataAsMap":{
                  "response":{
                     "Languages":[
                        {
                           "LanguageCode":"zh",
                           "Score":1.0
                        }
                     ]
                  }
               }
            }
         ],
         "status_code":200
      }
   ]
}
Create an ingest pipeline that uses the Amazon Comprehend API to annotate the languageThe next step is to create a pipeline in OpenSearch that calls the Amazon Comprehend API and adds the results of the call to the document being indexed. To do this, you provide both an  and an . You use these to tell OpenSearch what to send to the API and how to handle what comes back from the call.path = '/_ingest/pipeline/comprehend_language_identification_pipeline'
url = host + path

payload = {
  "description": "ingest identify lang with the comprehend API",
  "processors":[
    {
      "ml_inference": {
        "model_id": comprehend_model_id,
        "input_map": [
            {
               "Text": "Text"
            }
        ],
        "output_map": [
            {  
               "detected_language": "response.Languages[0].LanguageCode",
               "language_score": "response.Languages[0].Score"
            }
        ]
      }
    }
  ]
}
headers = {"Content-Type": "application/json"}
response = requests.put(url, auth=awsauth, json=payload, headers=headers)
You can see from the preceding code that you are pulling back both the top language result and its score from Amazon Comprehend and adding those fields to the document.Part 2: The Amazon Bedrock ML connectorIn this section, you use Amazon OpenSearch with Amazon Bedrock through the ml-commons plugin to perform a multilingual semantic search. Make sure that you have the solution prerequisites in place before attempting this section.In the SageMaker instance that was deployed for you, you can see the following files: , , .These documents have sentences in their respective languages that talk about the term  in different contexts. These contexts include spring as a verb meaning to move suddenly, as a noun meaning the season of spring, and finally spring as a noun meaning a mechanical part. In this section, you deploy Amazon Titan Text Embeddings model v2 using the ml connector for Amazon Bedrock. You then use this embeddings model to create vectors of text in three languages by ingesting the different language JSON files. Finally, these vectors are stored in Amazon OpenSearch to enable semantic searches to be used across the language sets.Amazon Bedrock provides streamlined access to various powerful AI foundation models through a single API interface. This managed service includes models from Amazon and other leading AI companies. You can test different models to find the ideal match for your specific needs, while maintaining security, privacy, and responsible AI practices. The service enables you to customize these models with your own data through methods such as fine-tuning and Retrieval Augmented Generation (RAG). Additionally, you can use Amazon Bedrock to create AI agents that can interact with enterprise systems and data, making it a comprehensive solution for developing generative AI applications.The reference architecture in the preceding figure shows the components used in this solution.(1) First we must create the OpenSearch ML connector via running code within the Amazon SageMaker notebook. The connector essentially creates a Rest API call to any model, we specifically want to create a connector to call the Titan Embeddings model within Amazon Bedrock.(2) Next, we must create an index to later index our language documents into. When creating an index, you can specify its mappings, settings, and aliases.(3) After creating an index within Amazon OpenSearch, we want to create an OpenSearch Ingestion pipeline that will allow us to streamline data processing and preparation for indexing, making it easier to manage and utilize the data. (4) Now that we have created an index and set up a pipeline, we can start indexing our documents into the pipeline.(5 – 6) We use the pipeline in OpenSearch that calls the Titan Embeddings model API. We send our language documents to the titan embeddings model, and the model returns vector embeddings of the sentences.(7) We store the vector embeddings within our index and perform vector semantic search.While this post highlights only specific areas of the overall solution, the SageMaker notebook has the code and instructions to run the full demo yourself.Before you can use Amazon Bedrock, you need to make sure that OpenSearch can call Amazon Bedrock. .Load sentences from the JSON documents into dataframesStart by loading the JSON document sentences into dataframes for more structured organization. Each row can contain the text, embeddings, and additional contextual information:import json
import pandas as pd

def load_sentences(file_name):
    sentences = []
    with open(file_name, 'r', encoding='utf-8') as file:
        for line in file:
            try:
                data = json.loads(line)
                if 'sentence' in data and 'sentence_english' in data:
                    sentences.append({
                        'sentence': data['sentence'],
                        'sentence_english': data['sentence_english']
                    })
            except json.JSONDecodeError:
                # Skip lines that are not valid JSON (like the index lines)
                continue

    return pd.DataFrame(sentences)

# Usage
german_df = load_sentences('german.json')
english_df = load_sentences('english.json')
french_df = load_sentences('french.json')
# print(french_df.head())Create the OpenSearch ML connector to Amazon BedrockAfter loading the JSON documents into dataframes, you’re ready to set up the OpenSearch ML connector to connect Amazon Bedrock to OpenSearch.The connector needs the following information. 
  It needs a protocol. For this solution, use , which allows OpenSearch to use an IAM role to call Amazon Bedrock.Provide the same role used earlier to set up permissions for the  role.Provide the , model, dimensions of the model, and embedding type.The final call looks like the following:payload = {
  "name": "Amazon Bedrock Connector: embedding",
  "description": "The connector to bedrock Titan embedding model",
  "version": 1,
  "protocol": "aws_sigv4",
  "parameters": {
    "region": "us-east-1",
    "service_name": "bedrock",
    "model": "amazon.titan-embed-text-v2:0",
    "dimensions": 1024,
    "normalize": True,
    "embeddingTypes": ["float"]
  },
  "credential": {
    "roleArn": sageMakerOpenSearchRoleArn
  },
  "actions": [
    {
      "action_type": "predict",
      "method": "POST",
      "url": "https://bedrock-runtime.${parameters.region}.amazonaws.com/model/${parameters.model}/invoke",
      "headers": {
        "content-type": "application/json",
        "x-amz-content-sha256": "required"
      },
      "request_body": "{ \"inputText\": \"${parameters.inputText}\", \"dimensions\": ${parameters.dimensions}, \"normalize\": ${parameters.normalize}, \"embeddingTypes\": ${parameters.embeddingTypes} }",
      "pre_process_function": "connector.pre_process.bedrock.embedding",
      "post_process_function": "connector.post_process.bedrock.embedding"
    }
  ]
}

bedrock_connector_response = requests.post(url, auth=awsauth, json=payload, headers=headers)

bedrock_connector_3 = bedrock_connector_response.json()["connector_id"]
print('Connector id: ' + bedrock_connector_3)
Test the Amazon Titan Embeddings model in OpenSearchAfter registering and deploying the Amazon Titan Embeddings model using the Amazon Bedrock connector, you can test the API to verify that it was set up and configured correctly. To do this, make the following call to OpenSearch:headers = {"Content-Type": "application/json"}
payload = {
  "parameters": {
    "inputText": "It's nice to see the flowers bloom and hear the birds sing in the spring"
  }
}
response = requests.post(url, auth=awsauth, json=payload, headers=headers)
print(response.json())You should get a formatted result, similar to the following, from the call that shows the generated embedding from the Amazon Titan Embeddings model:{'inference_results': [{'output': [{'name': 'sentence_embedding', 'data_type': 'FLOAT32', 'shape': [1024], 'data': [-0.04092199727892876, 0.052057236433029175, -0.03354490175843239, 0.04398418962955475, -0.001235315459780395, -0.03284895047545433, -0.014197427779436111, 0.0098129278048…The preceding result is significantly shortened compared to the actual embedding result you might receive. The purpose of this snippet is to show you the format.Create the index pipeline that uses the Amazon Titan Embeddings modelCreate a pipeline in OpenSearch. You use this pipeline to tell OpenSearch to send the fields you want embeddings for to the embeddings model.pipeline_name = "titan_embedding_pipeline_v2"
url = f"{host}/_ingest/pipeline/{pipeline_name}"

pipeline_body = {
    "description": "Titan embedding pipeline",
    "processors": [
        {
            "text_embedding": {
                "model_id": bedrock_model_id,
                "field_map": {
                    "sentence": "sentence_vector"
                }
            }
        }
    ]
}

response = requests.put(url, auth=awsauth, json=pipeline_body, headers={"Content-Type": "application/json"})
print(response.text)
With the pipeline in place, the next step is to create an index that will use the pipeline. There are three fields in the index: – This is where the vector embedding will be stored when returned from Amazon Bedrock. – This is the non-English language sentence. – this is the English translation of the sentence. Include this to see how well the model is translating the original sentence.index_name = 'bedrock-knn-index-v2'
url = f'{host}/{index_name}'
mapping = {
    "mappings": {
        "properties": {
            "sentence_vector": {
                "type": "knn_vector",
                "dimension": 1024,  
                "method": {
                    "name": "hnsw",
                    "space_type": "l2",
                    "engine": "nmslib"
                },
                "store":True
            },
            "sentence":{
                "type": "text",
                "store": True
            },
            "sentence_english":{
                "type": "text",
                "store": True
            }
        }
    },
    "settings": {
        "index": {
            "knn": True,
            "knn.space_type": "cosinesimil",
            "default_pipeline": pipeline_name
        }
    }
}

response = requests.put(url, auth=awsauth, json=mapping, headers={"Content-Type": "application/json"})
print(f"Index creation response: {response.text}")
Load dataframes into the indexEarlier in this section, you loaded the sentences from the JSON documents into dataframes. Now, you can index the documents and generate embeddings for them using the Amazon Titan Text Embeddings Model v2. The embeddings will be stored in the  field.index_name = "bedrock-knn-index-v2"

def index_documents(df, batch_size=100):
    total = len(df)
    for start in range(0, total, batch_size):
        end = min(start + batch_size, total)
        batch = df.iloc[start:end]

        bulk_data = []
        for _, row in batch.iterrows():
            # Prepare the action metadata
            action = {
                "index": {
                    "_index": index_name
                }
            }
            # Prepare the document data
            doc = {
                "sentence": row['sentence'],
                "sentence_english": row['sentence_english']
            }

            # Add the action and document to the bulk data
            bulk_data.append(json.dumps(action))
            bulk_data.append(json.dumps(doc))

        # Join the bulk data with newlines
        bulk_body = "\n".join(bulk_data) + "\n"

        # Send the bulk request
        bulk_url = f"{host}/_bulk"
        response = requests.post(bulk_url, auth=awsauth, data=bulk_body, headers={"Content-Type": "application/x-ndjson"})

        if response.status_code == 200:
            print(f"Successfully indexed batch {start}-{end} of {total}")
        else:
            print(f"Error indexing batch {start}-{end} of {total}: {response.text}")

        # Optional: add a small delay to avoid overwhelming the cluster
        time.sleep(1)

# Index your documents
print("Indexing German documents:")
index_documents(german_df)
print("\nIndexing English documents:")
index_documents(english_df)
print("\nIndexing French documents:")
index_documents(french_df)
Perform semantic k-NN across the documentsThe final step is to perform a k-nearest neighbor (k-NN) search across the documents.# Define your OpenSearch host and index name
index_name = "bedrock-knn-index-v2"
def semantic_search(query_text, k=5):
    search_url = f"{host}/{index_name}/_search"
    # First, index the query to generate its embedding
    index_doc = {
        "sentence": query_text,
        "sentence_english": query_text  # Assuming the query is in English
    }
    index_url = f"{host}/{index_name}/_doc"
    index_response = requests.post(index_url, auth=awsauth, json=index_doc, headers={"Content-Type": "application/json"})

    if index_response.status_code != 201:
        print(f"Failed to index query document: {index_response.text}")
        return []

    # Retrieve the indexed query document to get its vector
    doc_id = index_response.json()['_id']
    get_url = f"{host}/{index_name}/_doc/{doc_id}"
    get_response = requests.get(get_url, auth=awsauth)
    query_vector = get_response.json()['_source']['sentence_vector']

    # Now perform the KNN search
    search_query = {
        "size": 30,
        "query": {
            "knn": {
                "sentence_vector": {
                    "vector": query_vector,
                    "k": 30
                }
            }
        },
        "_source": ["sentence", "sentence_english"]
    }

    search_response = requests.post(search_url, auth=awsauth, json=search_query, headers={"Content-Type": "application/json"})

    if search_response.status_code != 200:
        print(f"Search failed with status code {search_response.status_code}")
        print(search_response.text)
        return []

    # Clean up - delete the temporary query document
    delete_url = f"{host}/{index_name}/_doc/{doc_id}"
    requests.delete(delete_url, auth=awsauth)

    return search_response.json()['hits']['hits']

# Example usage
query = "le soleil brille"
results = semantic_search(query)

if results:
    print(f"Search results for: '{query}'")
    for result in results:
        print(f"Score: {result['_score']}")
        print(f"Sentence: {result['_source']['sentence']}")
        print(f"English: {result['_source']['sentence_english']}")
        print()
else:
    print("No results found or search failed.")
The example query is in French and can be translated to . Keeping in mind that the JSON documents have sentences that use  in different contexts, you’re looking for query results and vector matches of sentences that use spring in the context of the season of spring.Here are some of the results from this query:Search results for: ' le soleil brille'
Score: 0.40515712
Sentence: Les premiers rayons de soleil au printemps réchauffent la terre.
English: The first rays of spring sunshine warm the earth.

Score: 0.40117615
Sentence: Die ersten warmen Sonnenstrahlen kitzeln auf der Haut im Frühling.
English: The first warm sun rays tickle the skin in spring.

Score: 0.3999985
Sentence: Die ersten Sonnenstrahlen im Frühling wecken die Lebensgeister.
English: The first rays of sunshine in spring awaken the spirits.
This shows that the model can provide results across all three languages. It is important to note that the confidence scores for these results might be low because you’ve only ingested a couple documents with a handful of sentences in each for this demo. To increase confidence scores and accuracy, ingest a robust dataset with multiple languages and plenty of sentences for reference.To avoid incurring future charges, go to the AWS Management Console for CloudFormation console and delete the stack you deployed. This will terminate the resources used in this solution.Benefits of using the ML connector for machine learning model integration with OpenSearchThere are many ways you can perform k-nn semantic vector searches; a popular methods is to deploy external Hugging Face sentence transformer models to a SageMaker endpoint. The following are the benefits of using the ML connector approach we showed in this post, and why should you use it instead of deploying models to a SageMaker endpoint:Simplified architecture 
  Native OpenSearch integrationOperational benefits 
  Less infrastructure to maintainBuilt-in scaling with OpenSearchSimplified security modelStraightforward updates and maintenanceCost efficiency 
  Pay-per-use Amazon Bedrock pricingNo endpoint management costsNow that you’ve seen how you can use the OpenSearch ML connector to augment your data with external REST calls, we recommend that you visit the GitHub repo if you haven’t already and walk through the full demo yourselves. The full demo shows how you can use Amazon Comprehend for language detection and how to use Amazon Bedrock for multilingual semantic vector search, using the ml-connector plugin for both use cases. It also has sample text and JSON documents to ingest so you can see how the pipeline works. is a Principal Solutions Architect supporting the World Wide Public Sector with a focus on OpenSearch and Data Analytics. John has been working with public sector customers over the past 25 years helping them deliver mission capabilities. Outside of work, John likes to collect AWS certifications and compete in triathlons. is a Solutions Architect for Amazon Web Services (AWS) with a focus in Data Analytics & Machine Learning. She has been building solutions that drive cloud adoption and help empower organizations to make data-driven decisions within the public sector. Outside of work, she loves dancing, spending time with friends and family, and traveling.

I’ve been building *W++*, a scripting language that looks like Python but runs on the .NET runtime. It started as a fun side project, but it evolved into something surprisingly powerful — and potentially useful:- Python-style syntax with semicolon-based simplicity- Compiles to .NET IL with experimental JIT support- Can run interpreted or compiled- Built-in CLI for managing projects, running, and building- Supports importing NuGet packages and converts them to .ingot modules automatically - MIT licensed and fully open-sourceYou can even do things like: wpp import Newtonsoft.Json
let person = new JObject() person["name"] = "Alice" print person["name"];
Use Cases: Game scripting (Unity, OpenTK support in progress)Education (gentle intro to .NET without C# syntax)Embeddable scripting engine for .NET appsI’d love feedback, ideas, and thoughts. Thanks for reading — and if you’ve ever said “I wish Python ran on .NET,” this might be for you.

If you're looking to turn your Python code into a web app or a fully functional API, Flask is a great place to start. It's lightweight, easy to use, and highly adaptable — making it a popular choice for developers at all levels.In this guide, we’ll walk through how to build a simple RESTful API using Flask.What is Flask?
Flask is a micro web framework written in Python. “Micro” means it doesn’t come bundled with extra tools like a database layer or form validation — giving you full control to structure your app however you want.Setting Up Your First Flask API
We’ll create a small API for managing a collection of books. No database for now — we’ll use an in-memory list to simulate stored data.Install Flask
Open your terminal and install Flask using pip:from flask import Flask, jsonify, requestbooks = [
    {"id": 1, "title": "1984", "author": "George Orwell"},
    {"id": 2, "title": "Brave New World", "author": "Aldous Huxley"}
]@app.route("/books", methods=["GET"])
def get_books():
    return jsonify(books), 200@app.route("/books/", methods=["GET"])
def get_book(id):
    book = next((b for b in books if b["id"] == id), None)
    return (jsonify(book), 200) if book else ({"error": "Book not found"}, 404)@app.route("/books", methods=["POST"])
def add_book():
    data = request.get_json()
    new_book = {
        "id": books[-1]["id"] + 1 if books else 1,
        "title": data["title"],
    }
    return jsonify(new_book), 201if  == "":
    app.run(debug=True)You should see the list of books in JSON format!Why Use Flask?
Simple to get started
Great for building APIs and microservices
Works well with SQLAlchemy, Jinja, and other tools
You only include what you needWhat’s Next?
Try extending the API by adding:
DELETE /books/ to remove a book
PUT /books/ to update an existing book
Integration with a SQLite database using SQLAlchemyWrap-Up
Flask is a fast and flexible way to get a Python web service running. Whether you’re building a prototype, a full-stack app, or a backend for a mobile project, Flask gives you just what you need — no more, no less.Have questions or want to see the next step with databases or deployment? Let me know in the comments!

In Part 1, we built user authentication and JWT middleware. Now in Part 2, we’ll implement CRUD operations for blog posts, each protected by JWT authentication. Only the post owner can update/delete their post.


  Database Model for Blog Posts
package models

type Post struct {
    ID        uint   `json:"id" gorm:"primaryKey"`
    Title     string `json:"title"`
    Content   string `json:"content"`
    UserID    uint   `json:"user_id"`
    CreatedAt time.Time
}

Make sure this model is auto-migrated:db.AutoMigrate(&models.Post{})
func CreatePost(c *gin.Context) {
    var post models.Post

    if err := c.ShouldBindJSON(&post); err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }

    // Check if user exists
    var user models.User
    if err := config.DB.First(&user, post.UserID).Error; err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": "User not found"})
        return
    }

    if err := config.DB.Create(&post).Error; err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to create post"})
        return
    }

    c.JSON(http.StatusCreated, post)
}




  Get All Posts & Single Post

type PostResponse struct {
    ID      uint       `json:"id"`
    Title   string     `json:"title"`
    Content string     `json:"content"`
    User    SimpleUser `json:"user"`
}

// SimpleUser represents a simplified user structure for responses
type SimpleUser struct {
    ID       uint   `json:"id"`
    Username string `json:"username"`
}

func GetPosts(c *gin.Context) {
    var posts []models.Post
    if err := config.DB.Preload("User").Find(&posts).Error; err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to fetch posts"})
        return
    }

    // PostResponse represents the response structure for a post with user info

    var responsePosts []PostResponse
    for _, post := range posts {
        responsePosts = append(responsePosts, PostResponse{
            ID:      uint(post.ID),
            Title:   post.Title,
            Content: post.Content,
            User: SimpleUser{
                ID:       post.User.ID,
                Username: post.User.Username,
            },
        })
    }

    c.JSON(http.StatusOK, responsePosts)
}

func GetPost(c *gin.Context) {
    idParam := c.Param("id")
    if idParam == "" {
        c.JSON(http.StatusBadRequest, gin.H{"error": "ID parameter is required"})
        return
    }

    id, err := strconv.Atoi(idParam)
    if err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid ID"})
        return
    }

    var post models.Post
    if err := config.DB.Preload("User").First(&post, id).Error; err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": "Post not found"})
        return
    }

    response := PostResponse{
        ID:      uint(post.ID),
        Title:   post.Title,
        Content: post.Content,
        User: SimpleUser{
            ID:       post.User.ID,
            Username: post.User.Username,
        },
    }

    c.JSON(http.StatusOK, response)
}

Only the owner can update the post:func UpdatePost(c *gin.Context) {
    id, err := strconv.Atoi(c.Param("id"))
    if err != nil || id <= 0 {
        c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid post ID"})
        return
    }

    var updatedPost models.Post
    if err := c.ShouldBindJSON(&updatedPost); err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }

    var post models.Post
    if err := config.DB.First(&post, id).Error; err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": "Post not found"})
        return
    }

    if post.UserID != updatedPost.UserID {
        c.JSON(http.StatusUnauthorized, gin.H{"error": "You are not the author of this post"})
        return
    }

    // Update the fields
    post.Title = updatedPost.Title
    post.Content = updatedPost.Content

    if err := config.DB.Save(&post).Error; err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update post"})
        return
    }

    c.JSON(http.StatusOK, post)
}

func DeletePost(c *gin.Context) {
    id, err := strconv.Atoi(c.Param("id"))
    if err != nil || id <= 0 {
        c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid post ID"})
        return
    }

    var payload struct {
        UserID uint `json:"user_id"`
    }
    if err := c.ShouldBindJSON(&payload); err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }

    var post models.Post
    if err := config.DB.First(&post, id).Error; err != nil {
        c.JSON(http.StatusNotFound, gin.H{"error": "Post not found"})
        return
    }

    if post.UserID != payload.UserID {
        c.JSON(http.StatusUnauthorized, gin.H{"error": "You are not the author of this post"})
        return
    }

    if err := config.DB.Delete(&post).Error; err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to delete post"})
        return
    }

    c.JSON(http.StatusOK, gin.H{"message": "Post deleted"})
}



  Protecting Routes with JWT
Update your routes/routes.go:auth := router.Group("/api")
auth.Use(middleware.JWTAuthMiddleware())

auth.POST("/posts", handlers.CreatePost)
auth.PUT("/posts/:id", handlers.UpdatePost)
auth.DELETE("/posts/:id", handlers.DeletePost)

// Public routes
router.GET("/posts", handlers.GetPosts)
router.GET("/posts/:id", handlers.GetPost)
Use Postman or ThunderClient:POST /api/posts → Add Bearer Token or Cookie
GET /posts → Public
PUT/DELETE /api/posts/:id → Must be ownerSearch & filter by title/user
Pagination
User-specific blog dashboard
